<script setup>
import {computed, onMounted, ref} from 'vue'
import {useRoute} from 'vue-router'
import {useApi} from '@directus/extensions-sdk'
import {format} from 'date-fns'
import html2canvas from 'html2canvas'
import jsPDF from 'jspdf'

const route = useRoute()
const orderId = route.query.id
const api = useApi()
const id = 'print-form'
const innerWidth = window.innerWidth
const orderBgPng = 'data:image/png;base64,'
const hetongImg = 'data:image/jpeg;base64,'


const printerData = ref({})

let orderbgsrc = 'https://forus-assets-1255436385.file.myqcloud.com/lafibre_order_bg.png'
onMounted(async () => {
  const res = await api.get(`/items/order/${orderId}?fields=*.*,order_sku_detail.*.*`)
  const orderInfo = res.data.data
  let advancePrice = 0

  orderInfo.order_payment.forEach((payment) => {
    advancePrice += payment.price
  })

  orderInfo.advancePrice = advancePrice
  printerData.value = orderInfo
})
function savePDF() {
  setTimeout(() => {
    html2canvas(document.getElementById(id)).then(canvas => {
      const a4Width = 595.28
      const a4Height = 841.89

      const options = {
        scale: 1
      }

      const canvasWidth = canvas.width / options.scale
      const canvasHeight = canvas.height / options.scale

      // 页面等比例缩放后宽高
      const pageWidth = a4Width
      const pageHeight = (a4Width / canvasWidth) * canvasHeight

      const doc = new jsPDF('p', 'pt', 'a4')
      // doc.addImage(canvas.toDataURL('image/jpeg', 1), 'JPEG', 0, 0, pageWidth, pageHeight)
      doc.addImage(document.getElementById('hetong-img'), 'JPEG', 0,0,pageWidth, pageHeight)
      doc.addPage();
      doc.addImage(canvas.toDataURL('image/jpeg', 1), 'JPEG', 0, 0, pageWidth, pageHeight)

      doc.save(`西装消费结算单-${printerData.value.id}.pdf`)
      // document.querySelector("#test").appendChild(canvas)
    })
  }, 100)

}

function printNow() {
  const iframe = document.createElement('iframe')
  iframe.setAttribute('id', 'print-iframe')
  document.body.appendChild(iframe)
  const doc = iframe.contentWindow.document
  const resetCss = document.createElement('style')
  iframe.contentDocument.head.appendChild(resetCss)

  doc.write(`<body>
<style>
*{margin: 0;padding:0} body{
--container-width: 100vw;
}
@page {
            size: A4;
            margin: 0;
            padding: 0;
        }
        @media print {

  body {
    height: 297mm * 2; /* A4高度x2 */
    overflow: hidden;  /* 隐藏第三页内容 */
  }
            .page-break {
                page-break-before: always;
                break-before: page;
            }
            .force-page-break {
                page-break-after: always;
                break-after: page;
                height: 0;
                visibility: hidden;
            }
        }
        .hetong-img{
        display: block !important;
        }
</style>
${document.getElementById(id).innerHTML}
</body>`)

  doc.close()
  iframe.contentWindow.focus()
  iframe.style.visibility = 'hidden'

  setTimeout(() => {
    iframe.contentWindow.print()
  }, 1000)

  setTimeout(() => {
    document.body.removeChild(iframe)
  }, 3000)
}
const container = ref(null)
const containerWidthPx = computed(() => {
  if (container.value) {
    return `${container.value.clientWidth}px`
  }else {
    return '0px'
  }
})
const containerWidth = computed(() => {
  if (container.value) {
    return `${container.value.clientWidth}`
  }else {
    return '0'
  }
})
</script>

<template>
  <private-view title="订单打印">
    <div>
      <v-button @click="savePDF">下载PDF</v-button>
      <v-button @click="printNow">直接打印</v-button>
      <div
          ref="container"

:style="{
      overflow: 'hidden',
      background: '#fff',
    color: '#000',
    maxWidth: '1000px',
'--container-width': containerWidthPx,
    }">

        <div
:id="id"
             class="order-font-family"
             :style="{
        position:'relative',
    background: '#fff',
    width:'100%'
    }">

<!--          :style="{-->
<!--          display: showHetongImg ? 'block': 'none'-->
<!--          }"-->

          <img
              id="hetong-img"
              style="width: 100%; page-break-after: avoid;display: none"
              class="hetong-img"
              :src="hetongImg"
               alt="">
          <div style="position: relative;font-size: 12px;">
          <img :src="orderBgPng" alt="" style="width: 100%" :style='{ position: "relative", marginTop: "calc(var(--container-width) * 0.0403)", width: "100%", }'/>

          <div :style='{position: "absolute", top: `calc(var(--container-width) * 0.2857)`, left: "calc(var(--container-width) * 0.1261)"}'>{{ printerData.id }}</div>
          <div :style='{position: "absolute", top: `calc(var(--container-width) * 0.3454)`, left: "calc(var(--container-width) * 0.1463)"}'>{{ printerData.customer?.name }}</div>
          <div :style='{position: "absolute", top: "calc(var(--container-width) * 0.3454)", left: "calc(var(--container-width) * 0.4513)"}'>{{ printerData.customer?.phone }}</div>
          <div :style='{position: "absolute", top: "calc(var(--container-width) * 0.3454)", left: "calc(var(--container-width) * 0.7731)", whiteSpace: "nowrap"}'>{{
              format(new Date(
                  printerData.date_updated), 'yyyy-MM-dd HH:mm')
            }}
          </div>
          <div :style='{position: "absolute", top: "calc(var(--container-width) * 0.3882)", left: "calc(var(--container-width) * 0.1471)"}'>{{ printerData?.customer?.address }}</div>
          <div :style='{position: "absolute", top: "calc(var(--container-width) * 0.3882)", left: "calc(var(--container-width) * 0.7462)", whiteSpace: "nowrap"}'>{{
              format(new Date(
                  printerData?.customer?.weddingDate), 'yyyy-MM-dd')
            }}
          </div>

          <div :style='{position: "absolute", top: "calc(var(--container-width) * 0.8487)", left: "calc(var(--container-width) * 0.7983)"}'>
            {{ printerData.real_price }}(<s>{{ printerData.total_price }}</s>)
          </div>
          <div :style='{position: "absolute", top: "calc(var(--container-width) * 0.8899)", left: "calc(var(--container-width) * 0.7983)"}'>{{ printerData.advancePrice }}</div>
          <div :style='{position: "absolute", top: "calc(var(--container-width) * 0.9311)", left: "calc(var(--container-width) * 0.7983)"}'>{{
              +printerData.real_price -
              printerData.advancePrice
            }}
          </div>
          <div :style='{position: "absolute", top: "calc(var(--container-width) * 0.9706)", left: "calc(var(--container-width) * 0.1807)"}'>{{ printerData.remark }}</div>

          <div :style='{position: "absolute", top: "calc(var(--container-width) * 1.1118)", left: "calc(var(--container-width) * 0.2261)"}'>{{ printerData.user?.first_name }}</div>

          <div :style='{position: "absolute", top: "calc(var(--container-width) * 0.5059)", left: "calc(var(--container-width) * 0.0487)"}'>
            <div v-for="item in printerData.order_sku_detail" :key="item.id" style="display:flex">
              <div :style='{width: "calc(var(--container-width) * 0.3)"}'>{{ item?.sku?.name }}{{ item?.classify?.name }}</div>
              <div :style='{width: "calc(var(--container-width) * 0.3891)"}'>{{ item?.sku?.code }}</div>
              <div :style='{width: "calc(var(--container-width) * 0.1101)"}'>{{ 1 }}</div>
              <div :style='{width: "calc(var(--container-width) * 0.1025)",textAlign:"right"}'>{{ item?.price }} <span :style='{width: "calc(var(--container-width) * 0.0168)"}'></span>RMB
              </div>
            </div>
          </div>
          </div>
        </div>
      </div>
    </div>
  </private-view>
</template>
